  8â†’import kotlinx.datetime.format.*
  9â†’import kotlinx.datetime.internal.JSJoda.Instant as jtInstant
 10â†’import kotlinx.datetime.internal.JSJoda.OffsetDateTime as jtOffsetDateTime
 11â†’import kotlinx.datetime.internal.JSJoda.Duration as jtDuration
 12â†’import kotlinx.datetime.internal.JSJoda.Clock as jtClock
 13â†’import kotlinx.datetime.internal.JSJoda.ChronoUnit as jtChronoUnit
 14â†’import kotlinx.datetime.internal.JSJoda.ZonedDateTime as jtZonedDateTime
 15â†’import kotlinx.datetime.internal.safeAdd
 16â†’import kotlinx.datetime.internal.*
 17â†’import kotlinx.datetime.serializers.InstantIso8601Serializer
 18â†’import kotlinx.serialization.Serializable
 19â†’import kotlin.time.*
 20â†’import kotlin.time.Duration.Companion.nanoseconds
 21â†’import kotlin.time.Duration.Companion.seconds
 22â†’
 23â†’@Serializable(with = InstantIso8601Serializer::class)
 24â†’public actual class Instant internal constructor(internal val value: jtInstant) : Comparable<Instant> {
 25â†’
 26â†’    public actual val epochSeconds: Long
 27â†’        get() = value.epochSecond().toLong()
 28â†’    public actual val nanosecondsOfSecond: Int
 29â†’        get() = value.nano().toInt()
 30â†’
 31â†’    public actual fun toEpochMilliseconds(): Long =
 32â†’            epochSeconds * MILLIS_PER_ONE + nanosecondsOfSecond / NANOS_PER_MILLI
 33â†’
 34â†’    public actual operator fun plus(duration: Duration): Instant = duration.toComponents { seconds, nanoseconds ->
 35â†’        return try {
 36â†’            Instant(plusFix(seconds.toDouble(), nanoseconds))
 37â†’        } catch (e: Throwable) {
 38â†’            if (!e.isJodaDateTimeException()) throw e
 39â†’            if (duration.isPositive()) MAX else MIN
 40â†’        }
 41â†’    }
 42â†’
 43â†’    internal fun plusFix(seconds: Double, nanos: Int): jtInstant {
 44â†’        val newSeconds = value.epochSecond() + seconds
 45â†’        val newNanos = value.nano() + nanos
 46â†’        return jsTry { jtInstant.ofEpochSecond(newSeconds, newNanos.toInt()) }
 47â†’    }
 48â†’
 49â†’    public actual operator fun minus(duration: Duration): Instant = plus(-duration)
 50â†’
 51â†’    public actual operator fun minus(other: Instant): Duration {
 52â†’        val diff = jtDuration.between(other.value, this.value)
 53â†’        return diff.seconds().seconds + diff.nano().nanoseconds
 54â†’    }
 55â†’
 56â†’    public actual override operator fun compareTo(other: Instant): Int = this.value.compareTo(other.value)
 57â†’
 58â†’    override fun equals(other: Any?): Boolean =
 59â†’            (this === other) || (other is Instant && (this.value === other.value || this.value.equals(other.value)))
 60â†’
 61â†’    override fun hashCode(): Int = value.hashCode()
 62â†’
 63â†’    actual override fun toString(): String = value.toString()
 64â†’
 65â†’    public actual companion object {
 66â†’        @Deprecated("Use Clock.System.now() instead", ReplaceWith("Clock.System.now()", "kotlinx.datetime.Clock"), level = DeprecationLevel.ERROR)
 67â†’        public actual fun now(): Instant =
 68â†’                Instant(jtClock.systemUTC().instant())
 69â†’
 70â†’        public actual fun fromEpochMilliseconds(epochMilliseconds: Long): Instant = try {
 71â†’            fromEpochSeconds(epochMilliseconds / MILLIS_PER_ONE, epochMilliseconds % MILLIS_PER_ONE * NANOS_PER_MILLI)
 72â†’        } catch (e: Throwable) {
 73â†’            if (!e.isJodaDateTimeException()) throw e
 74â†’            if (epochMilliseconds > 0) MAX else MIN
 75â†’        }
 76â†’
 77â†’        public actual fun parse(input: CharSequence, format: DateTimeFormat<DateTimeComponents>): Instant =
 78â†’            if (format === DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET) {
 79â†’                try {
 80â†’                    Instant(jsTry { jtOffsetDateTime.parse(fixOffsetRepresentation(input.toString())) }.toInstant())
 81â†’                } catch (e: Throwable) {
 82â†’                    if (e.isJodaDateTimeParseException()) throw DateTimeFormatException(e)
 83â†’                    throw e
 84â†’                }
 85â†’            } else {
 86â†’                try {
 87â†’                    format.parse(input).toInstantUsingOffset()
 88â†’                } catch (e: IllegalArgumentException) {
 89â†’                    throw DateTimeFormatException("Failed to parse an instant from '$input'", e)
 90â†’                }
 91â†’            }
 92â†’
 93â†’        @Deprecated("This overload is only kept for binary compatibility", level = DeprecationLevel.HIDDEN)
 94â†’        public fun parse(isoString: String): Instant = parse(input = isoString)
 95â†’
 96â†’        /** A workaround for the string representations of Instant that have an offset of the form
 97â†’         * "+XX" not being recognized by [jtOffsetDateTime.parse], while "+XX:XX" work fine. */
 98â†’        private fun fixOffsetRepresentation(isoString: String): String {
 99â†’            val time = isoString.indexOf('T', ignoreCase = true)
100â†’            if (time == -1) return isoString // the string is malformed
101â†’            val offset = isoString.indexOfLast { c -> c == '+' || c == '-' }
102â†’            if (offset < time) return isoString // the offset is 'Z' and not +/- something else
103â†’            val separator = isoString.indexOf(':', offset) // if there is a ':' in the offset, no changes needed
104â†’            return if (separator != -1) isoString else "$isoString:00"
105â†’        }
106â†’
107â†’        public actual fun fromEpochSeconds(epochSeconds: Long, nanosecondAdjustment: Long): Instant = try {
108â†’            /* Performing normalization here because otherwise this fails:
109â†’               assertEquals((Long.MAX_VALUE % 1_000_000_000).toInt(),
110â†’                            Instant.fromEpochSeconds(0, Long.MAX_VALUE).nanosecondsOfSecond) */
111â†’            val secs = safeAdd(epochSeconds, nanosecondAdjustment.floorDiv(NANOS_PER_ONE.toLong()))
112â†’            val nos = nanosecondAdjustment.mod(NANOS_PER_ONE.toLong()).toInt()
113â†’            Instant(jsTry { jtInstant.ofEpochSecond(secs.toDouble(), nos) })
114â†’        } catch (e: Throwable) {
115â†’            if (!e.isJodaDateTimeException() && e !is ArithmeticException) throw e
116â†’            if (epochSeconds > 0) MAX else MIN
117â†’        }
118â†’
119â†’        public actual fun fromEpochSeconds(epochSeconds: Long, nanosecondAdjustment: Int): Instant = try {
120â†’            Instant(jsTry { jtInstant.ofEpochSecond(epochSeconds.toDouble(), nanosecondAdjustment) })
121â†’        } catch (e: Throwable) {
122â†’            if (!e.isJodaDateTimeException()) throw e
123â†’            if (epochSeconds > 0) MAX else MIN
124â†’        }
125â†’
126â†’        public actual val DISTANT_PAST: Instant = Instant(jsTry { jtInstant.ofEpochSecond(DISTANT_PAST_SECONDS.toDouble(), 999_999_999) })
127â†’        public actual val DISTANT_FUTURE: Instant = Instant(jsTry { jtInstant.ofEpochSecond(DISTANT_FUTURE_SECONDS.toDouble(), 0) })
128â†’
129â†’        internal actual val MIN: Instant = Instant(jtInstant.MIN)
130â†’        internal actual val MAX: Instant = Instant(jtInstant.MAX)
131â†’    }
132â†’}
