135â†’public actual fun Instant.plus(period: DateTimePeriod, timeZone: TimeZone): Instant = try {
136â†’    val thisZdt = jsTry { this.value.atZone(timeZone.zoneId) }
137â†’    with(period) {
138â†’        thisZdt
139â†’                .run { if (totalMonths != 0) jsTry { plusMonths(totalMonths) } else this }
140â†’                .run { if (days != 0) jsTry { plusDays(days) } else this }
141â†’                .run { if (hours != 0) jsTry { plusHours(hours) } else this }
142â†’                .run { if (minutes != 0) jsTry { plusMinutes(minutes) } else this }
143â†’                .run { if (seconds != 0) jsTry { plusSeconds(seconds) } else this }
144â†’                .run { if (nanoseconds != 0) jsTry { plusNanos(nanoseconds.toDouble()) } else this }
145â†’    }.toInstant().let(::Instant)
146â†’}    catch (e: Throwable) {
147â†’    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e)
148â†’    throw e
149â†’}
