154â†’@Deprecated("Use the plus overload with an explicit number of units", ReplaceWith("this.plus(1, unit, timeZone)"))
155â†’public actual fun Instant.plus(unit: DateTimeUnit, timeZone: TimeZone): Instant =
156â†’        plus(1, unit, timeZone)
