158â†’public actual fun Instant.plus(value: Long, unit: DateTimeUnit, timeZone: TimeZone): Instant =
159â†’        try {
160â†’            val thisZdt = this.atZone(timeZone)
161â†’            when (unit) {
162â†’                is DateTimeUnit.TimeBased -> {
163â†’                    plus(value, unit).value.checkZone(timeZone)
164â†’                }
165â†’                is DateTimeUnit.DayBased ->
166â†’                    jsTry {thisZdt.plusDays(value.toDouble() * unit.days) }.toInstant()
167â†’                is DateTimeUnit.MonthBased ->
168â†’                    jsTry { thisZdt.plusMonths(value.toDouble() * unit.months) }.toInstant()
169â†’            }.let(::Instant)
170â†’        } catch (e: Throwable) {
171â†’            if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e)
172â†’            throw e
173â†’        }
