175â†’public actual fun Instant.plus(value: Int, unit: DateTimeUnit, timeZone: TimeZone): Instant =
176â†’        try {
177â†’            val thisZdt = this.atZone(timeZone)
178â†’            when (unit) {
179â†’                is DateTimeUnit.TimeBased ->
180â†’                    plus(value.toLong(), unit).value.checkZone(timeZone)
181â†’                is DateTimeUnit.DayBased ->
182â†’                    jsTry { thisZdt.plusDays(value.toDouble() * unit.days) }.toInstant()
183â†’                is DateTimeUnit.MonthBased ->
184â†’                    jsTry { thisZdt.plusMonths(value.toDouble() * unit.months) }.toInstant()
185â†’            }.let(::Instant)
186â†’        } catch (e: Throwable) {
187â†’            if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e)
188â†’            throw e
189â†’        }
