191â†’public actual fun Instant.minus(value: Int, unit: DateTimeUnit, timeZone: TimeZone): Instant =
192â†’    if (value == Int.MIN_VALUE)
193â†’        plus(-value.toLong(), unit, timeZone)
194â†’    else
195â†’        plus(-value, unit, timeZone)
