197â†’public actual fun Instant.plus(value: Long, unit: DateTimeUnit.TimeBased): Instant =
198â†’    try {
199â†’        multiplyAndDivide(value, unit.nanoseconds, NANOS_PER_ONE.toLong()).let { (d, r) ->
200â†’            Instant(plusFix(d.toDouble(), r.toInt()))
201â†’        }
202â†’    } catch (e: Throwable) {
203â†’        if (!e.isJodaDateTimeException()) {
204â†’            throw e
205â†’        }
206â†’        if (value > 0) Instant.MAX else Instant.MIN
207â†’    }
