209â†’public actual fun Instant.periodUntil(other: Instant, timeZone: TimeZone): DateTimePeriod = try {
210â†’    var thisZdt = jsTry { this.value.atZone(timeZone.zoneId) }
211â†’    val otherZdt = jsTry { other.value.atZone(timeZone.zoneId) }
212â†’
213â†’    val months = thisZdt.until(otherZdt, jtChronoUnit.MONTHS); thisZdt = jsTry { thisZdt.plusMonths(months) }
214â†’    val days = thisZdt.until(otherZdt, jtChronoUnit.DAYS); thisZdt = jsTry { thisZdt.plusDays(days) }
215â†’    val nanoseconds = thisZdt.until(otherZdt, jtChronoUnit.NANOS)
216â†’
217â†’    buildDateTimePeriod(months.toInt(), days.toInt(), nanoseconds.toLong())
218â†’} catch (e: Throwable) {
219â†’    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e) else throw e
220â†’}
