222â†’public actual fun Instant.until(other: Instant, unit: DateTimeUnit, timeZone: TimeZone): Long = try {
223â†’    val thisZdt = this.atZone(timeZone)
224â†’    val otherZdt = other.atZone(timeZone)
225â†’    when(unit) {
226â†’        is DateTimeUnit.TimeBased -> until(other, unit)
227â†’        is DateTimeUnit.DayBased -> (thisZdt.until(otherZdt, jtChronoUnit.DAYS) / unit.days).toLong()
228â†’        is DateTimeUnit.MonthBased -> (thisZdt.until(otherZdt, jtChronoUnit.MONTHS) / unit.months).toLong()
229â†’    }
230â†’} catch (e: ArithmeticException) {
231â†’    if (this < other) Long.MAX_VALUE else Long.MIN_VALUE
232â†’} catch (e: Throwable) {
233â†’    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e) else throw e
234â†’}
