 10â†’import kotlinx.datetime.internal.format.parser.Copyable
 11â†’import kotlin.math.*
 12â†’
 13â†’internal interface UtcOffsetFieldContainer {
 14â†’    var isNegative: Boolean?
 15â†’    var totalHoursAbs: Int?
 16â†’    var minutesOfHour: Int?
 17â†’    var secondsOfMinute: Int?
 18â†’}
 19â†’
 20â†’internal interface AbstractWithOffsetBuilder : DateTimeFormatBuilder.WithUtcOffset {
 21â†’    fun addFormatStructureForOffset(structure: FormatStructure<UtcOffsetFieldContainer>)
 22â†’
 23â†’    override fun offsetHours(padding: Padding) =
 24â†’        addFormatStructureForOffset(
 25â†’            SignedFormatStructure(
 26â†’                BasicFormatStructure(UtcOffsetWholeHoursDirective(padding)),
 27â†’                withPlusSign = true
 28â†’            )
 29â†’        )
 30â†’
 31â†’    override fun offsetMinutesOfHour(padding: Padding) =
 32â†’        addFormatStructureForOffset(BasicFormatStructure(UtcOffsetMinuteOfHourDirective(padding)))
 33â†’
 34â†’    override fun offsetSecondsOfMinute(padding: Padding) =
 35â†’        addFormatStructureForOffset(BasicFormatStructure(UtcOffsetSecondOfMinuteDirective(padding)))
 36â†’
 37â†’    @Suppress("NO_ELSE_IN_WHEN")
 38â†’    override fun offset(format: DateTimeFormat<UtcOffset>) = when (format) {
 39â†’        is UtcOffsetFormat -> addFormatStructureForOffset(format.actualFormat)
 40â†’    }
 41â†’}
 42â†’
 43â†’internal class UtcOffsetFormat(override val actualFormat: CachedFormatStructure<UtcOffsetFieldContainer>) :
 44â†’    AbstractDateTimeFormat<UtcOffset, IncompleteUtcOffset>() {
 45â†’    companion object {
 46â†’        fun build(block: DateTimeFormatBuilder.WithUtcOffset.() -> Unit): UtcOffsetFormat {
 47â†’            val builder = Builder(AppendableFormatStructure())
 48â†’            builder.block()
 49â†’            return UtcOffsetFormat(builder.build())
 50â†’        }
 51â†’    }
 52â†’
 53â†’    private class Builder(override val actualBuilder: AppendableFormatStructure<UtcOffsetFieldContainer>) :
 54â†’        AbstractDateTimeFormatBuilder<UtcOffsetFieldContainer, Builder>, AbstractWithOffsetBuilder {
 55â†’
 56â†’        override fun addFormatStructureForOffset(structure: FormatStructure<UtcOffsetFieldContainer>) {
 57â†’            actualBuilder.add(structure)
 58â†’        }
 59â†’
 60â†’        override fun createEmpty(): Builder = Builder(AppendableFormatStructure())
 61â†’    }
 62â†’
 63â†’    override fun intermediateFromValue(value: UtcOffset): IncompleteUtcOffset =
 64â†’        IncompleteUtcOffset().apply { populateFrom(value) }
 65â†’
 66â†’    override fun valueFromIntermediate(intermediate: IncompleteUtcOffset): UtcOffset = intermediate.toUtcOffset()
 67â†’
 68â†’    override val emptyIntermediate: IncompleteUtcOffset get() = emptyIncompleteUtcOffset
 69â†’
 70â†’}
 71â†’
 72â†’internal enum class WhenToOutput {
 73â†’    NEVER,
 74â†’    IF_NONZERO,
 75â†’    ALWAYS;
 76â†’}
 77â†’
 78â†’internal fun <T : DateTimeFormatBuilder> T.outputIfNeeded(whenToOutput: WhenToOutput, format: T.() -> Unit) {
 79â†’    when (whenToOutput) {
 80â†’        WhenToOutput.NEVER -> {}
 81â†’        WhenToOutput.IF_NONZERO -> {
 82â†’            optional {
 83â†’                format()
 84â†’            }
 85â†’        }
 86â†’
 87â†’        WhenToOutput.ALWAYS -> {
 88â†’            format()
 89â†’        }
 90â†’    }
 91â†’}
 92â†’
 93â†’internal fun DateTimeFormatBuilder.WithUtcOffset.isoOffset(
 94â†’    zOnZero: Boolean,
 95â†’    useSeparator: Boolean,
 96â†’    outputMinute: WhenToOutput,
 97â†’    outputSecond: WhenToOutput
 98â†’) {
 99â†’    require(outputMinute >= outputSecond) { "Seconds cannot be included without minutes" }
100â†’    fun DateTimeFormatBuilder.WithUtcOffset.appendIsoOffsetWithoutZOnZero() {
101â†’        offsetHours()
102â†’        outputIfNeeded(outputMinute) {
103â†’            if (useSeparator) {
104â†’                char(':')
105â†’            }
106â†’            offsetMinutesOfHour()
107â†’            outputIfNeeded(outputSecond) {
108â†’                if (useSeparator) {
109â†’                    char(':')
110â†’                }
111â†’                offsetSecondsOfMinute()
112â†’            }
113â†’        }
114â†’    }
115â†’    if (zOnZero) {
116â†’        optional("Z") {
117â†’            alternativeParsing({
118â†’                char('z')
119â†’            }) {
120â†’                appendIsoOffsetWithoutZOnZero()
121â†’            }
122â†’        }
123â†’    } else {
124â†’        appendIsoOffsetWithoutZOnZero()
125â†’    }
126â†’}
