208â†’private class UtcOffsetMinuteOfHourDirective(private val padding: Padding) :
209â†’    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
210â†’        OffsetFields.minutesOfHour,
211â†’        minDigits = padding.minDigits(2), spacePadding = padding.spaces(2)
212â†’    ) {
213â†’
214â†’    override val builderRepresentation: String
215â†’        get() = when (padding) {
216â†’            Padding.NONE -> "${DateTimeFormatBuilder.WithUtcOffset::offsetMinutesOfHour.name}()"
217â†’            else -> "${DateTimeFormatBuilder.WithUtcOffset::offsetMinutesOfHour.name}(${padding.toKotlinCode()})"
218â†’        }
219â†’
220â†’    override fun equals(other: Any?): Boolean = other is UtcOffsetMinuteOfHourDirective && padding == other.padding
221â†’    override fun hashCode(): Int = padding.hashCode()
