224â†’private class UtcOffsetSecondOfMinuteDirective(private val padding: Padding) :
225â†’    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
226â†’        OffsetFields.secondsOfMinute,
227â†’        minDigits = padding.minDigits(2), spacePadding = padding.spaces(2)
228â†’    ) {
229â†’
230â†’    override val builderRepresentation: String
231â†’        get() = when (padding) {
232â†’            Padding.NONE -> "${DateTimeFormatBuilder.WithUtcOffset::offsetSecondsOfMinute.name}()"
233â†’            else -> "${DateTimeFormatBuilder.WithUtcOffset::offsetSecondsOfMinute.name}(${padding.toKotlinCode()})"
234â†’        }
235â†’
236â†’    override fun equals(other: Any?): Boolean = other is UtcOffsetSecondOfMinuteDirective && padding == other.padding
