package kotlinx.datetime.test

import kotlinx.datetime.Instant
import kotlin.test.Test
import kotlin.test.assertEquals

class InstantParseIsoConsistencyTest {

    @Test
    fun parseIsoRequiresSeconds() {
        assertInvalidFormat("seconds are not optional in ISO_DATE_TIME_OFFSET") {
            Instant.parse("2024-03-19T17:50Z")
        }
        assertInvalidFormat("seconds are not optional in ISO_DATE_TIME_OFFSET") {
            Instant.parse("2024-03-19T17:50+00")
        }
    }

    @Test
    fun parseIsoAllowsOffsetHourWithoutMinutes() {
        assertEquals(
            Instant.parse("2024-03-19T14:50:00Z"),
            Instant.parse("2024-03-19T17:50:00+03")
        )
    }
}
"}

